script.text:

/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    ps_no: '[ps_no]:=[ps_no_nt]*[$ty_gia]',
    ps_co: '[ps_co]:=[ps_co_nt]*[$ty_gia]',
    ps_no_nt: '[ps_no_nt]:= [ps_no_nt]',
    ps_co_nt: '[ps_co_nt]:= [ps_co_nt]',

    t_ps_no: ['t_ps_no', 'ps_no'],
    t_ps_co: ['t_ps_co', 'ps_co'],
    t_ps_no_nt: ['t_ps_no_nt', 'ps_no_nt'],
    t_ps_co_nt: ['t_ps_co_nt', 'ps_co_nt']
  };
  udf$Detail$(g);
  udf$Detail$PaymentControl(g);
}
function udf$Detail$PaymentControl(g) {
  if (!g.get_element().parentForm._udfPaymentControl) {
    udf$Field$(g, 'ma_tt');
    udf$Field$(g, 'so_ct0');
    udf$Field$(g, 'ngay_ct0');
  }
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}
function onChange$GridVoucherDetail$Account(o) {o.grid.request(o, 'Account', 'Account', ['tk'], o);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'ps_no_nt':
      g.executeExpression(o, ['[ps_co_nt]:=0']);
      g.validExpression(o, [g.$a.ps_no, g.$a.ps_co], [g.$a.t_ps_no_nt, g.$a.t_ps_co_nt, g.$a.t_ps_no, g.$a.t_ps_co], null, 'ps_co_nt');
      break;
    case 'ps_co_nt':
      g.executeExpression(o, ['[ps_no_nt]:=0']);
      g.validExpression(o, [g.$a.ps_co, g.$a.ps_no], [g.$a.t_ps_no_nt, g.$a.t_ps_co_nt, g.$a.t_ps_no, g.$a.t_ps_co], null, null);
      break;
    case 'ps_no':
      g.executeExpression(o, ['[ps_co]:=0']);
      g.validExpression(o, null, [g.$a.t_ps_no, g.$a.t_ps_co], null, 'ps_co');
      break;
    case 'ps_co':
      g.executeExpression(o, ['[ps_no]:=0']);
      g.validExpression(o, null, [g.$a.t_ps_no, g.$a.t_ps_co], null, null);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      if (g._rowCount > 1) {
        var d1 = f.getItemValue('t_ps_no_nt') - f.getItemValue('t_ps_co_nt'), d2 = f.getItemValue('t_ps_no') - f.getItemValue('t_ps_co');
        if (d1 > 0) {
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_co_nt'), d1);
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_co'), d2);
        }
        else {
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_no_nt'), -d1);
          g._setItemValue(g._rowCount, g._getColumnOrder('ps_no'), -d2);
        }
        on$GridVoucherDetail$RowChange(g, f);
      }
      break;
    case 'Check':
      g.validRowExpression('ma_kh', '(![tk_cn]) || ([ma_kh] != "")');
      break;
    case 'ImportData':
      if (f._action == 'View') break;
      g.showForm('JPDetailImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
   case 'Account':
      g.setItemGridBehavior(o, [['tk_cn', result[0].Value, '', false]]);
      break;
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_ps_no_nt, g.$a.t_ps_co_nt, g.$a.t_ps_no, g.$a.t_ps_co]);}
/* </flatten> */

      &DowloadScript;
